        String s = sin.nextLine();
        long num=0;
        int k=0;
        for(int i=s.length()-1;i>=0;i--)
        {
            if((s.charAt(i)>='A'&&s.charAt(i)<='Z')||(s.charAt(i)>='a' &&s.charAt(i)<='z'))
